import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String name = reader.readLine();

            // Sanitize and escape user input using ESAPI library
            String safeName = "";
            try {
                safeName = ESAPI.encoder().encodeForHTML(name);
            } catch (EncodingException e) {
                System.out.println("Error sanitizing input.");
            }

            System.out.println("Welcome, " + safeName + "!");
        } catch (IOException e) {
            System.out.println("An error occurred.");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
